class TestSelectFrames(unittest.TestCase):
    @staticmethod
    def _video(n, prefix="f"):
        return {"frames": [{"image_path": f"{prefix}{i}"} for i in range(n)]}

    def test_no_frames(self):
        self.assertEqual(_select_frames([self._video(0)]), [])
        self.assertEqual(_select_frames([]), [])

    def test_video_missing_frames_key(self):
        self.assertEqual(_select_frames([{"url": "u"}]), [])

    def test_under_and_at_limit_returns_all(self):
        self.assertEqual(len(_select_frames([self._video(3)])), 3)
        self.assertEqual(len(_select_frames([self._video(8)])), 8)

    def test_over_limit_samples_evenly(self):
        frames = _select_frames([self._video(100)])
        self.assertEqual(len(frames), 8)
        self.assertEqual(frames[0]["image_path"], "f0")   # first kept
        self.assertEqual(frames[-1]["image_path"], "f99")  # last kept
        paths = [f["image_path"] for f in frames]
        self.assertEqual(len(paths), len(set(paths)))      # no duplicates

    def test_combines_frames_across_videos(self):
        frames = _select_frames([self._video(2, "a"), self._video(2, "b")])
        self.assertEqual(
            [f["image_path"] for f in frames], ["a0", "a1", "b0", "b1"]
        )

    def test_max_images_one_does_not_crash(self):
        frames = _select_frames([self._video(10)], max_images=1)
        self.assertEqual(len(frames), 1)


