class TestBuildMessages(unittest.TestCase):
    def _videos(self, tmp, n_frames=2):
        frames = []
        for i in range(n_frames):
            path = os.path.join(tmp, f"frame_{i}.jpg")
            with open(path, "wb") as f:
                f.write(b"jpeg")
            frames.append({"image_path": path})
        return [
            {
                "url": "https://youtu.be/jNQXAC9IVRw",
                "title": "Demo",
                "transcript": "hello",
                "frames": frames,
            }
        ]

    def test_structure_and_image_count(self):
        with tempfile.TemporaryDirectory() as tmp:
            messages = build_messages(self._videos(tmp))
        self.assertEqual(messages[0]["role"], "system")
        self.assertEqual(messages[1]["role"], "user")
        blocks = messages[1]["content"]
        self.assertEqual(blocks[0]["type"], "text")
        self.assertIn("hello", blocks[0]["text"])
        images = [b for b in blocks if b["type"] == "image_url"]
        self.assertEqual(len(images), 2)
        self.assertTrue(
            images[0]["image_url"]["url"].startswith("data:image/jpeg;base64,")
        )

    def test_caps_images_at_eight(self):
        with tempfile.TemporaryDirectory() as tmp:
            messages = build_messages(self._videos(tmp, n_frames=15))
        images = [
            b for b in messages[1]["content"] if b["type"] == "image_url"
        ]
        self.assertEqual(len(images), 8)

    def test_missing_transcript_and_title_fall_back(self):
        videos = [{"url": "https://youtu.be/jNQXAC9IVRw", "frames": []}]
        messages = build_messages(videos)
        text = messages[1]["content"][0]["text"]
        self.assertIn("(no transcript)", text)
        self.assertIn("https://youtu.be/jNQXAC9IVRw", text)

    def test_image_detail_env_var(self):
        with tempfile.TemporaryDirectory() as tmp:
            videos = self._videos(tmp, n_frames=1)
            with mock.patch.dict(
                os.environ, {"OPENAI_IMAGE_DETAIL": "low"}
            ):
                with_detail = build_messages(videos)
            env = {
                k: v for k, v in os.environ.items()
                if k != "OPENAI_IMAGE_DETAIL"
            }
            with mock.patch.dict(os.environ, env, clear=True):
                without_detail = build_messages(videos)
        img = [
            b for b in with_detail[1]["content"] if b["type"] == "image_url"
        ][0]
        self.assertEqual(img["image_url"]["detail"], "low")
        img = [
            b for b in without_detail[1]["content"] if b["type"] == "image_url"
        ][0]
        self.assertNotIn("detail", img["image_url"])


