class TestSaveMockups(unittest.TestCase):
    def test_saves_files_and_returns_paths(self):
        mockups = [
            {"screen_name": "Dashboard", "html": "<html>1</html>"},
            {"screen_name": "Feature Page", "html": "<html>2</html>"},
        ]
        with tempfile.TemporaryDirectory() as tmp:
            out = os.path.join(tmp, "mockups")
            paths = save_mockups(mockups, output_dir=out)
            self.assertEqual(len(paths), 2)
            self.assertTrue(paths[0].endswith("dashboard.html"))
            self.assertTrue(paths[1].endswith("feature_page.html"))
            for path, mockup in zip(paths, mockups):
                with open(path, encoding="utf-8") as f:
                    self.assertEqual(f.read(), mockup["html"])

    def test_sanitizes_unsafe_screen_names(self):
        # Model output can contain characters invalid in Windows filenames.
        mockups = [
            {"screen_name": "Login / Sign-Up: Step 1", "html": "<html/>"},
            {"screen_name": "///", "html": "<html/>"},
        ]
        with tempfile.TemporaryDirectory() as tmp:
            paths = save_mockups(mockups, output_dir=tmp)
        self.assertTrue(paths[0].endswith("login_sign-up_step_1.html"))
        self.assertTrue(paths[1].endswith("screen_2.html"))

